// モジュールA: java.sqlへの推移的依存を宣言
module com.example.moduleA {
    requires transitive java.sql;
    exports com.example.moduleA.api;
}

// モジュールB: moduleAに依存
module com.example.moduleB {
    requires com.example.moduleA;
    // java.sqlもrequiresなしで使える（transitive効果）
}

module com.example.library {
    // すべてのモジュールに公開
    exports com.example.library.api;

    // 特定のモジュールだけに公開
    exports com.example.library.internal
        to com.example.app, com.example.test;
}

// パッケージ単位でリフレクションを許可
module com.example.app {
    opens com.example.app.model;
    opens com.example.app.entity to hibernate.core;
}

// モジュール全体をリフレクションに公開
open module com.example.app {
    exports com.example.app.api;
}

