// java.baseは自動的にrequiresされるため
// 以下の2つは同じ意味
module com.example.app {
    // requires java.base; // 書かなくてよい（暗黙的）
    requires java.sql;
}

// java.lang, java.util, java.io は
// java.base に含まれるので常に使用可能
import java.util.List;      // OK
import java.io.IOException; // OK

module com.example.app {
    // データベースアクセスに必要
    requires java.sql;
    // ロギング機能に必要
    requires java.logging;
    // GUI開発に必要
    requires java.desktop;

    exports com.example.app.api;
}

